const banned = ['N/A', '(無資料)', '無資料', '待補', '...(依命盤填)'];
const hits = banned.filter(b => output.includes(b));
if (hits.length === 0) return true;
return { pass: false, reason: `命中禁用占位符:${hits.join(', ')}` };

const stars = (output.match(/★/g) || []).length;
// 矩陣 105 + TOP 5 優勢 5 條 ●●●●○ + TOP 5 風險 5 條 + 12 月 ★ 表 ~72 個
// 保守估計矩陣本身 105、其餘 80+、總 ★ ≥ 180 才合格
if (stars >= 180) return true;
return { pass: false, reason: `★ 數量 ${stars} < 180、矩陣可能不完整` };

const hasCodeBlock = /```[\s\S]*?(1\s*月|1月)[\s\S]*?(12\s*月|12月)[\s\S]*?```/.test(output);
const monthLabels = ['1月','2月','3月','4月','5月','6月','7月','8月','9月','10月','11月','12月'];
const monthsFound = monthLabels.filter(m => output.includes(m)).length;
if (hasCodeBlock && monthsFound >= 12) return true;
return { pass: false, reason: `ASCII 曲線:hasCodeBlock=${hasCodeBlock}、12 月標籤命中 ${monthsFound}/12` };

const dotCount = (output.match(/●●●/g) || []).length;
if (dotCount >= 10) return true;
return { pass: false, reason: `信心度 ●●● 命中 ${dotCount} < 10、TOP 5 優勢+風險不齊` };

const guji = (output.match(/《[^》]{2,30}》/g) || []);
const unique = new Set(guji);
if (guji.length >= 15) return true;
return { pass: false, reason: `古籍引用 ${guji.length} < 15(unique=${unique.size})、不滿 15 系統各 1 條` };

const wordCount = output.replace(/\s/g, '').length;
if (wordCount >= 6000 && wordCount <= 18000) return true;
return { pass: false, reason: `字數 ${wordCount} 超出 6000-18000 範圍(目標 9000-15000、Call 3 集大成)` };

